import re

# Load the data
data_file = locals()['var_functions.query_db:12']
with open(data_file, 'r') as f:
    all_records = json.load(f)

# Parse CPC level 4 codes and collect filing data
cpc_filing_data = {}  # CPC level 4 code -> {year: count}

# Month mapping
month_map = {
    'jan': 1, 'january': 1, 'feb': 2, 'february': 2, 'mar': 3, 'march': 3,
    'apr': 4, 'april': 4, 'may': 5, 'jun': 6, 'june': 6,
    'jul': 7, 'july': 7, 'aug': 8, 'august': 8, 'sep': 9, 'september': 9,
    'oct': 10, 'october': 10, 'nov': 11, 'november': 11, 'dec': 12, 'december': 12
}

# Function to extract CPC level 4 code
def get_cpc_level4(code):
    # Remove any trailing whitespace
    code = code.strip()
    # Split by / to get main group
    parts = code.split('/')
    if len(parts) >= 1:
        main_group = parts[0]
        # For level 4, we want the first 5-6 characters typically
        # Section (1) + Class (2) + Subclass (1) + Main group (1-2)
        # Examples: B41F21 -> B41F21 (6 chars), B63B21 -> B63B21 (6 chars)
        #           H04W72 -> H04W72 (6 chars)
        if len(main_group) >= 5:
            return main_group
    return None

# Function to parse grant date and extract month/year
def parse_grant_date(date_str):
    if not date_str or '2019' not in date_str:
        return None

    # Find month in the date string
    for month_abbr, month_num in month_map.items():
        if month_abbr in date_str.lower():
            return month_num, 2019

    return None

# Function to extract CPC codes
def extract_cpc_codes(cpc_str):
    if not cpc_str:
        return []

    try:
        cpc_data = json.loads(cpc_str.strip())
        return [item['code'] for item in cpc_data if isinstance(item, dict) and 'code' in item]
    except:
        return []

# Process all records
german_h2_2019_patents = []

for record in all_records:
    patents_info = record.get('Patents_info', '')
    grant_date = record.get('grant_date', '')
    cpc_str = record.get('cpc', '')

    # Check if German patent
    if not ('DE-' in patents_info or 'Germany' in patents_info or 'German' in patents_info):
        continue

    # Parse date
    date_result = parse_grant_date(grant_date)
    if date_result is None:
        continue

    month, year = date_result

    # Check if H2 of 2019
    if year != 2019 or month < 7:
        continue

    # Extract CPC codes
    cpc_codes = extract_cpc_codes(cpc_str)
    if not cpc_codes:
        continue

    # Get level 4 CPC codes
    level4_codes = set()
    for code in cpc_codes:
        level4 = get_cpc_level4(code)
        if level4:
            level4_codes.add(level4)

    if not level4_codes:
        continue

    german_h2_2019_patents.append({
        'patents_info': patents_info,
        'grant_date': grant_date,
        'month': month,
        'cpc_level4_codes': list(level4_codes)
    })

    # Track filing data per CPC level 4 code
    for cpc_level4 in level4_codes:
        if cpc_level4 not in cpc_filing_data:
            cpc_filing_data[cpc_level4] = {2019: 0}
        cpc_filing_data[cpc_level4][2019] += 1

print(f"German H2 2019 patents: {len(german_h2_2019_patents)}")
print(f"CPC level 4 codes found: {len(cpc_filing_data)}")

# Show distribution
sample_cpc = dict(list(cpc_filing_data.items())[:10])
print("Sample CPC codes:", sample_cpc)

print('__RESULT__:')
print(json.dumps({
    'german_h2_2019_patents_count': len(german_h2_2019_patents),
    'cpc_level4_codes_count': len(cpc_filing_data),
    'sample_cpc_data': sample_cpc,
    'all_cpc_codes': list(cpc_filing_data.keys())[:50]
}))"}

