        return False
    return 'DE-' in patents_info or 'Germany' in patents_info or 'German' in patents_info

def parse_grant_date(date_str):
    if not date_str:
        return None

    # Extract year
    year_match = re.search(r'\b(201[5-9]|202[0-4])\b', date_str)
    if not year_match:
        return None

    year = int(year_match.group(1))

    # Extract month
    month_num = None
    for month_abbr, month_val in month_map.items():
        if month_abbr in date_str.lower():
            month_num = month_val
            break

    if month_num is None:
        return None

    return month_num, year

def extract_cpc_codes(cpc_str):
    if not cpc_str:
        return []
    try:
        cpc_data = json.loads(cpc_str.strip())
        return [item['code'] for item in cpc_data if isinstance(item, dict) and 'code' in item]
    except:
        return []

def get_cpc_level4(code):
    code = code.strip()
    parts = code.split('/')
    if len(parts) >= 1:
        main_group = parts[0]
        # Extract first 5-6 characters for level 4
        # Section (1) + Class (2) + Subclass (1) + Main group (1-2)
        if len(main_group) >= 5:
            return main_group
    return None

# Collect historical filing data for German patents
cpc_filing_history = defaultdict(lambda: defaultdict(int))  # cpc_level4 -> year -> count
german_patents_processed = 0

for record in all_records:
    patents_info = record.get('Patents_info', '')
    grant_date = record.get('grant_date', '')
    cpc_str = record.get('cpc', '')

    if not is_german_patent(patents_info):
        continue

    date_result = parse_grant_date(grant_date)
    if date_result is None:
        continue

    month, year = date_result
    if year < 2015 or year > 2024:  # Limit to reasonable range
        continue

    cpc_codes = extract_cpc_codes(cpc_str)
    if not cpc_codes:
        continue

    german_patents_processed += 1

    level4_codes = set()
    for code in cpc_codes:
        level4 = get_cpc_level4(code)
        if level4:
            level4_codes.add(level4)

    for cpc_level4 in level4_codes:
        cpc_filing_history[cpc_level4][year] += 1

print(f"German patents processed: {german_patents_processed}")
print(f"CPC level 4 codes found: {len(cpc_filing_history)}")

# Show sample data
sample_cpc = dict(list(cpc_filing_history.items())[:5])
