{"code": "import json
import re
from collections import defaultdict

# Load patent data
data_file = locals()['var_functions.query_db:12']
with open(data_file, 'r') as f:
    all_records = json.load(f)

# Define parsing functions
month_map = {
    'jan': 1, 'january': 1, 'feb': 2, 'february': 2, 'mar': 3, 'march': 3,
    'apr': 4, 'april': 4, 'may': 5, 'jun': 6, 'june': 6,
    'jul': 7, 'july': 7, 'aug': 8, 'august': 8, 'sep': 9, 'september': 9,
    'oct': 10, 'october': 10, 'nov': 11, 'november': 11, 'dec': 12, 'december': 12
}

def is_german_patent(patents_info):
    if not patents_info:
        return False
    return 'DE-' in patents_info or 'Germany' in patents_info or 'German' in patents_info

def parse_grant_date(date_str):
    if not date_str:
        return None

    # Extract year
    year_match = re.search(r'\b(201[5-9]|202[0-4])\b', date_str)
    if not year_match:
        return None

    year = int(year_match.group(1))

    # Extract month
    month_num = None
    for month_abbr, month_val in month_map.items():
        if month_abbr in date_str.lower():
            month_num = month_val
            break

    if month_num is None:
        return None

    return month_num, year

def extract_cpc_codes(cpc_str):
    if not cpc_str:
        return []
    try:
        cpc_data = json.loads(cpc_str.strip())
        return [item['code'] for item in cpc_data if isinstance(item, dict) and 'code' in item]
    except:
        return []

def get_cpc_level4(code):
    code = code.strip()
    parts = code.split('/')
    if len(parts) >= 1:
        main_group = parts[0]
        # For level 4, we take the full main group (section + class + subclass + main group)
        if len(main_group) >= 5:
            return main_group
    return None

# Collect German patents and their CPC data
german_h2_2019_patents = []
cpc_filing_data = defaultdict(lambda: defaultdict(int))  # cpc_level4 -> year -> count

for record in all_records:
    patents_info = record.get('Patents_info', '')
    grant_date = record.get('grant_date', '')
    cpc_str = record.get('cpc', '')

    if not is_german_patent(patents_info):
        continue

    # Parse date
    date_result = parse_grant_date(grant_date)
    if date_result is None:
        continue

    month, year = date_result

    # Skip if not H2 2019
    if year != 2019 or month < 7:
        continue

    # Extract CPC codes
    cpc_codes = extract_cpc_codes(cpc_str)
    if not cpc_codes:
        continue

    # Get level 4 codes
    level4_codes = set()
    for code in cpc_codes:
        level4 = get_cpc_level4(code)
        if level4:
            level4_codes.add(level4)

    if not level4_codes:
        continue

    german_h2_2019_patents.append({
        'patents_info': patents_info,
        'grant_date': grant_date,
        'month': month,
        'cpc_level4_codes': list(level4_codes)
    })

    # Update filing counts for 2019
    for cpc_level4 in level4_codes:
        cpc_filing_data[cpc_level4][2019] += 1

print('German H2 2019 patents found: ' + str(len(german_h2_2019_patents)))
print('CPC level 4 codes in these patents: ' + str(len(cpc_filing_data)))

# Sort CPC codes by filing count in 2019
sorted_cpc = sorted(cpc_filing_data.items(), key=lambda x: x[1][2019], reverse=True)

print('Top CPC level 4 codes by H2 2019 filings:')
for i, (cpc_code, data) in enumerate(sorted_cpc[:10]):
    print('  ' + str(i+1) + '. ' + cpc_code + ': ' + str(data[2019]) + ' filings')

print('__RESULT__:')
result = {
    'german_h2_2019_count': len(german_h2_2019_patents),
    'cpc_level4_codes_count': len(cpc_filing_data),
    'top_cpc_codes': [(code, dict(data)) for code, data in sorted_cpc[:20]]
}
print(json.dumps(result))"}

